queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?news_articles a :Articles .
    ?news_articles p:Title ?title .
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?feature_articles a :Feature_Articles .
    ?feature_articles p:Title ?title .
    ?feature_articles p:Word_Count ?word_count_f .
    FILTER((STR(?word_count_f) = "1000" || STR(?word_count_f) = "1000.0"))
    BIND(?title AS ?o0)
  }
}

